import{_ as o,H as a,f as t,i as r}from"./chunks/framework.DSMXSEqa.js";const p=JSON.parse('{"title":"Commands","description":"","frontmatter":{},"headers":[],"relativePath":"commands.md","filePath":"commands.md"}'),c={name:"commands.md"};function n(i,e,s,d,l,g){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h1><h3 id="gotouch" tabindex="-1">gotouch <a class="header-anchor" href="#gotouch" aria-label="Permalink to &quot;gotouch&quot;">​</a></h3><p>gotouch command uses <a href="./customize/properties-yaml.html">properties yaml</a> file for prompting user to enter name and select project structure. If file flag value is not provided, it is going to use <a href="https://raw.githubusercontent.com/denizgursoy/go-touch-projects/main/package.yaml" target="_blank" rel="noreferrer">default properties yaml</a>. Firstly,The command asks for project name. Project name is written to go module and used for directory name.</p><p><strong><code>inline</code></strong>: Inline flag allows you to create projects in the working directory.</p><h3 id="package" tabindex="-1">package <a class="header-anchor" href="#package" aria-label="Permalink to &quot;package&quot;">​</a></h3><p><code>gotouch package --source path-to-source --target path-to-target</code></p><p>Package command compresses the source directory with the .tar.gz extension and moves the zip file to target directory. <code>source</code> and <code>target</code> flags are optional. Default values for <code>source</code> and <code>target</code> are <code>./</code>, <code>../</code> respectively.</p><p>Package command ignores following files/directories:</p><ol><li><em><strong>__MACOS</strong></em></li><li><em><strong>.DS_Store</strong></em></li><li><em><strong>.idea</strong></em></li><li><em><strong>.vscode</strong></em></li><li><em><strong>.git</strong></em></li></ol><h3 id="validate" tabindex="-1">validate <a class="header-anchor" href="#validate" aria-label="Permalink to &quot;validate&quot;">​</a></h3><p><code>gotouch validate --file path-to-yaml</code></p><p>Validate checks if your yaml is valid or not.</p><h3 id="config" tabindex="-1">config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;config&quot;">​</a></h3><p><code>gotouch config</code></p><p>Allows you to change following configurations:</p><p><strong><code>url</code></strong>: Replaces the default URL. If changed, Gotouch will display project structures in the URL without <code>-f</code> flag.</p><p>Usage:</p><p><code>gotouch config set url path-to-new-url</code> changes to default URL</p><p><code>gotouch config unset url</code> removes the changed URL to default.</p>',19)])])}const h=o(c,[["render",n]]);export{p as __pageData,h as default};
